INSERT INTO public.vocabulary_examples (id, vocab_id, japanese, reading, translation) VALUES
('ex_n3_auto_1', 'v_n3_auto_1', 'どんなに難しくても諦めないでください。', 'どんなに むずかしくても あきらめないで ください。', 'Sesulit apapun, tolong jangan menyerah.'),
('ex_n3_auto_2', 'v_n3_auto_2', '先生は遅刻した学生を怒った。', 'せんせいは ちこくした がくせいを おこった。', 'Guru memarahi siswa yang terlambat.'),
('ex_n3_auto_3', 'v_n3_auto_3', '突然の知らせに皆が驚いた。', 'とつぜんの しらせに みなが おどろいた。', 'Semua orang terkejut dengan kabar yang tiba-tiba.'),
('ex_n3_auto_4', 'v_n3_auto_4', '深呼吸して落ち着いてください。', 'しんこきゅうして おちついて ください。', 'Tolong tarik napas dalam-dalam dan tenang.'),
('ex_n3_auto_5', 'v_n3_auto_5', 'たくさんの候補の中から一つを選んだ。', 'たくさんの こうほの なかから ひとつを えらんだ。', 'Aku memilih satu dari banyak kandidat.'),
('ex_n3_auto_6', 'v_n3_auto_6', '状況に応じて対応を変えてください。', 'じょうきょうに おうじて たいおうを かえて ください。', 'Tolong ubah penanganan sesuai situasi.'),
('ex_n3_auto_7', 'v_n3_auto_7', '彼は自分が正しいと思い込んでいる。', 'かれは じぶんが ただしいと おもいこんでいる。', 'Dia yakin sekali bahwa dirinya benar.'),
('ex_n3_auto_8', 'v_n3_auto_8', '財布を忘れたことに途中で気づいた。', 'さいふを わすれたことに とちゅうで きづいた。', 'Aku menyadari di tengah jalan bahwa aku lupa dompet.'),
('ex_n3_auto_9', 'v_n3_auto_9', '丁寧に相手の申し出を断った。', 'ていねいに あいての もうしでを ことわった。', 'Aku menolak tawaran lawan bicara dengan sopan.'),
('ex_n3_auto_10', 'v_n3_auto_10', '予約の前に内容を確認してください。', 'よやくの まえに ないようを かくにんして ください。', 'Tolong periksa isinya sebelum memesan.'),
('ex_n3_auto_11', 'v_n3_auto_11', '春の暖かさを体全体で感じた。', 'はるの あたたかさを からだ ぜんたいで かんじた。', 'Aku merasakan kehangatan musim semi dengan seluruh tubuh.'),
('ex_n3_auto_12', 'v_n3_auto_12', 'この問題は環境に関係することだ。', 'この もんだいは かんきょうに かんけいする ことだ。', 'Masalah ini berkaitan dengan lingkungan.'),
('ex_n3_auto_13', 'v_n3_auto_13', '会議で新しい方針を決定した。', 'かいぎで あたらしい ほうしんを けっていした。', 'Kebijakan baru ditetapkan dalam rapat.'),
('ex_n3_auto_14', 'v_n3_auto_14', 'あのとき諦めたことを後悔している。', 'あのとき あきらめたことを こうかいしている。', 'Aku menyesal karena menyerah saat itu.'),
('ex_n3_auto_15', 'v_n3_auto_15', '突然の変更で皆が混乱した。', 'とつぜんの へんこうで みなが こんらんした。', 'Semua orang kebingungan karena perubahan mendadak.'),
